drop extension if exists "pg_net";

create extension if not exists "vector" with schema "public";

create sequence "public"."kb_id_seq";

create sequence "public"."report_categories_id_seq";


  create table "public"."chat_logs" (
    "chat_id" bigint generated by default as identity not null,
    "session_id" text,
    "prompt" text,
    "response" text,
    "git_version" text,
    "created_at" timestamp with time zone default now()
      );


alter table "public"."chat_logs" enable row level security;


  create table "public"."chat_logs_kb" (
    "chat_log_kb_id" bigint generated by default as identity not null,
    "chat_id" bigint not null,
    "kb_id" text not null,
    "created_at" timestamp with time zone default now(),
    "similarity" double precision
      );


alter table "public"."chat_logs_kb" enable row level security;


  create table "public"."error_logs" (
    "id" bigint generated always as identity not null,
    "error_id" text,
    "error_message" text,
    "session_id" text,
    "git_version" text,
    "created_at" timestamp with time zone default now()
      );


alter table "public"."error_logs" enable row level security;


  create table "public"."knowledge_base" (
    "kb_id" text not null default ('vox-kb-'::text || lpad((nextval('public.kb_id_seq'::regclass))::text, 4, '0'::text)),
    "topico" text,
    "eixo_tematico" text,
    "descricao" text not null,
    "referencias" text,
    "tags" text[],
    "autor" text,
    "created_at" timestamp with time zone default now(),
    "kb_count" numeric,
    "embedding" public.vector(768),
    "modificado_em" timestamp with time zone default now()
      );


alter table "public"."knowledge_base" enable row level security;


  create table "public"."knowledge_base_etl" (
    "kb_id" text not null default ('vox-kb-'::text || lpad((nextval('public.kb_id_seq'::regclass))::text, 4, '0'::text)),
    "topico" text,
    "eixo_tematico" text,
    "descricao" text not null,
    "referencias" text,
    "tags" text[],
    "autor" text,
    "created_at" timestamp with time zone default now(),
    "kb_count" numeric,
    "embedding" public.vector,
    "modificado_em" timestamp with time zone default now()
      );


alter table "public"."knowledge_base_etl" enable row level security;


  create table "public"."report_categories" (
    "id" integer not null default nextval('public.report_categories_id_seq'::regclass),
    "label" text,
    "description" text,
    "created_at" timestamp with time zone default now()
      );


alter table "public"."report_categories" enable row level security;


  create table "public"."sessions" (
    "session_id" text not null,
    "created_at" timestamp with time zone default now(),
    "id" bigint generated by default as identity not null
      );


alter table "public"."sessions" enable row level security;


  create table "public"."user_reports" (
    "id" bigint generated always as identity not null,
    "session_id" text,
    "git_version" text,
    "chat_history" text,
    "created_at" timestamp with time zone default now(),
    "category_id" bigint,
    "comment" text
      );


alter table "public"."user_reports" enable row level security;

alter sequence "public"."report_categories_id_seq" owned by "public"."report_categories"."id";

