CREATE INDEX idx_error_logs_session_id ON public.error_logs USING btree (session_id);

CREATE INDEX idx_kb_eixo ON public.knowledge_base USING btree (eixo_tematico);

CREATE INDEX idx_kb_embedding ON public.knowledge_base USING hnsw (embedding public.vector_cosine_ops);

CREATE INDEX idx_kb_topico ON public.knowledge_base USING btree (topico);

CREATE INDEX idx_user_reports_session_id ON public.user_reports USING btree (session_id);

CREATE UNIQUE INDEX knowledge_base_etl_pkey ON public.knowledge_base_etl USING btree (kb_id);

CREATE UNIQUE INDEX knowledge_base_pkey ON public.knowledge_base USING btree (kb_id);

CREATE UNIQUE INDEX report_categories_pkey ON public.report_categories USING btree (id);

CREATE UNIQUE INDEX sessions_id_key ON public.sessions USING btree (id);

CREATE UNIQUE INDEX sessions_pkey ON public.sessions USING btree (session_id);

CREATE UNIQUE INDEX user_reports_pkey ON public.user_reports USING btree (id);

alter table "public"."chat_logs" add constraint "chat_logs_pkey" PRIMARY KEY using index "chat_logs_pkey";

alter table "public"."chat_logs_kb" add constraint "chat_log_kb_pkey" PRIMARY KEY using index "chat_log_kb_pkey";

alter table "public"."error_logs" add constraint "error_logs_pkey" PRIMARY KEY using index "error_logs_pkey";

alter table "public"."knowledge_base" add constraint "knowledge_base_pkey" PRIMARY KEY using index "knowledge_base_pkey";

alter table "public"."knowledge_base_etl" add constraint "knowledge_base_etl_pkey" PRIMARY KEY using index "knowledge_base_etl_pkey";

alter table "public"."report_categories" add constraint "report_categories_pkey" PRIMARY KEY using index "report_categories_pkey";

