alter table "public"."user_reports" add constraint "user_reports_pkey" PRIMARY KEY using index "user_reports_pkey";

alter table "public"."chat_logs" add constraint "chat_logs_session_id_fkey" FOREIGN KEY (session_id) REFERENCES public.sessions(session_id) ON DELETE RESTRICT not valid;

alter table "public"."chat_logs" validate constraint "chat_logs_session_id_fkey";

alter table "public"."chat_logs_kb" add constraint "chat_log_kb_chat_id_fkey" FOREIGN KEY (chat_id) REFERENCES public.chat_logs(chat_id) ON UPDATE CASCADE not valid;

alter table "public"."chat_logs_kb" validate constraint "chat_log_kb_chat_id_fkey";

alter table "public"."chat_logs_kb" add constraint "chat_log_kb_chat_log_kb_id_key" UNIQUE using index "chat_log_kb_chat_log_kb_id_key";

alter table "public"."chat_logs_kb" add constraint "chat_log_kb_kb_id_fkey" FOREIGN KEY (kb_id) REFERENCES public.knowledge_base(kb_id) ON UPDATE CASCADE not valid;

alter table "public"."chat_logs_kb" validate constraint "chat_log_kb_kb_id_fkey";

alter table "public"."error_logs" add constraint "error_logs_session_id_fkey" FOREIGN KEY (session_id) REFERENCES public.sessions(session_id) ON DELETE RESTRICT not valid;

alter table "public"."error_logs" validate constraint "error_logs_session_id_fkey";

alter table "public"."sessions" add constraint "sessions_id_key" UNIQUE using index "sessions_id_key";

alter table "public"."user_reports" add constraint "user_reports_category_id_fkey" FOREIGN KEY (category_id) REFERENCES public.report_categories(id) ON UPDATE CASCADE not valid;

alter table "public"."user_reports" validate constraint "user_reports_category_id_fkey";

alter table "public"."user_reports" add constraint "user_reports_session_id_fkey" FOREIGN KEY (session_id) REFERENCES public.sessions(session_id) ON DELETE RESTRICT not valid;

alter table "public"."user_reports" validate constraint "user_reports_session_id_fkey";

set check_function_bodies = off;

CREATE OR REPLACE FUNCTION public.increment_kb_count()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
begin
  UPDATE knowledge_base
  set kb_count = kb_count + 1
  where kb_id = new.kb_id;
  return new;
end
$function$
;

CREATE OR REPLACE FUNCTION public.match_knowledge_base(query_embedding public.vector, match_threshold double precision, match_count integer, filter_topic text DEFAULT NULL::text)
 RETURNS TABLE(id text, topico text, eixo_tematico text, descricao text, similarity double precision)
 LANGUAGE plpgsql
AS $function$
  BEGIN
    return query
    select
      knowledge_base.kb_id,
      knowledge_base.topico,
      knowledge_base.eixo_tematico,
      knowledge_base.descricao,
      1 - (knowledge_base.embedding <=> query_embedding) as similarity
    from knowledge_base
    where 1 - (knowledge_base.embedding <=> query_embedding) > match_threshold
    and (filter_topic is null or knowledge_base.topico = filter_topic)
    order by knowledge_base.embedding <=> query_embedding
    limit match_count;
  END;
  $function$
;

CREATE OR REPLACE FUNCTION public.update_modificado_em()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    NEW.modificado_em = now();
    RETURN NEW;
END;
$function$
;

