CREATE TRIGGER tg_update_kb_usage AFTER INSERT ON public.chat_logs_kb FOR EACH ROW EXECUTE FUNCTION public.increment_kb_count();

CREATE TRIGGER update_kb_modificado_em BEFORE UPDATE ON public.knowledge_base FOR EACH ROW EXECUTE FUNCTION public.update_modificado_em();

CREATE TRIGGER update_kb_etl_modificado_em BEFORE UPDATE ON public.knowledge_base_etl FOR EACH ROW EXECUTE FUNCTION public.update_modificado_em();


